	.TITLE	PSION.ASM	.PROC	M6801CELL	=	16'2004UTW_S0	=	16'41UTW_S1	=	16'43UTW_S2	=	16'45UTW_S3	=	16'47UTW_S4	=	16'49UTW_S5	=	16'4BAMB_EI	=	16'2335AMB_DOIT=	16'234AAL_FREE	=	0		; libre un descripteur de celluleAL_GRAB	=	1		; cherche un descripteur de celluleAL_GROW	=	2		; agrandit une celluleAL_REPL	=	3		; ?AL_SHNK	=	4		; diminue une celluleAL_SIZE	=	5		; donne la taille d'une celluleAL_ZERO	=	6		; vide une celluleEXABIX	=	16'18		; instruction EX AB,IX	.LOC	0;-----------\\; IntDisable >;===========/; Empche les interruptions de venir regarder l'agenda.; Ceci est absolument ncessaire pendant que la mmoire; de l'agenda est modifie !; in	-; out	IX	valeur  sauver (AMB_EI); mod	toutIntDisable:	MOVE	AMB_EI,A	.8	EXABIX		; AMB_EI --> IX	MOVE	F,A	IOFF	CLR	AMB_EI	CLR	AMB_DOIT	MOVE	A,F	RET;----------\\; IntEnable >;==========/; Remet les interruptions de l'agenda  l'tat actif.; in	AB	valeur sauve (AMB_EI); out	-; mod	toutIntEnable:	CLR	AMB_EI	CLR	AMB_DOIT	MOVE	A,AMB_EI	RET;--------\\; GetMem  >;========/; Donne la taille de la mmoire de l'agenda courant.; in	-; out	IX	taille de la mmoire (0..n); mod	toutGetMem:	MOVE	#CELL,IX	TRAP	.8	AL_SIZE		; taille --> AB	.8	EXABIX		; EX AB,IX	DEC	IX		; ne compte pas le <0> terminateur	RET;--------\\; ClrMem  >;========/; Efface compltement l'agenda courant de la mmoire du PSION.; in	-; out	-; mod	toutClrMem:; Demande la taille actuelle de la cellule de l'agenda.	MOVE	#CELL,IX	TRAP	.8	AL_SIZE		; taille --> AB; Diminue la cellule de l'agenda pour qu'il ne reste plus; que le <0> terminateur.	MOVE	#0,IX	MOVE	IX,UTW_S0	.8	EXABIX	DEC	IX		; DEC AB	.8	EXABIX	JUMP,EQ R8^ZERO$	MOVE	#CELL,IX	TRAP	.8	AL_SHNK		; diminue la celluleZERO$:	RET;--------\\; NewMem  >;========/; Cre une nouvelle zone pour l'agenda dans la mmoire; du PSION (longueur donne dans AB).; ATTENTION: Il faut avoir fait CLRMEM avant !; IX est rendu pour permettre ensuite de remplir le contenu.; in	AB	nouvelle taille (sans le <0> terminateur); out	IX	^o mettre le data (BC bytes);		=0 si erreur; mod	toutNewMem:; Augmente la cellule de l'agenda selon la taille donne; en entre dans AB.	MOVE	#0,IX	MOVE	IX,UTW_S0	MOVE	#CELL,IX	TRAP	.8	AL_GROW		; augmente la cellule	JUMP,CS R8^ERROR$	MOVE	#CELL,IX	MOVE	{IX},IX	RETERROR$:	MOVE	#0,IX	RET